# Category: information_disclosure

import Foundation

class AnalyticsLogger {
    static let shared = AnalyticsLogger()
    
    private init() {}
    
    func logUserInteraction(event: String, userID: String?) {
        NSLog("User Interaction: \(event), User ID: \(userID ?? "N/A")")
    }
    
    func logAuthenticationFlow(step: String, email: String?, token: String?) {
        NSLog("Authentication Flow: \(step), Email: \(email ?? "N/A"), Token: \(token ?? "N/A")")
    }

    func logAPICall(url: String, method: String, requestPayload: [String: Any]?) {
        let requestPayloadString = requestPayload != nil ? String(describing: requestPayload!) : "N/A"
        NSLog("API Call - URL: \(url), Method: \(method), Request Payload: \(requestPayloadString)")
    }

    func logAPIResponse(url: String, method: String, responsePayload: [String: Any]?, error: Error?) {
        let responsePayloadString = responsePayload != nil ? String(describing: responsePayload!) : "N/A"
        if let error = error {
            NSLog("API Response - URL: \(url), Method: \(method), Error: \(error.localizedDescription)")
        } else {
            NSLog("API Response - URL: \(url), Method: \(method), Response Payload: \(responsePayloadString)")
        }
    }

    func logUserDataChange(userID: String, changedData: [String: Any]) {
        NSLog("User Data Change - User ID: \(userID), Changed Data: \(changedData)")
    }
    
    func logError(condition: String, description: String) {
        NSLog("Error Condition: \(condition), Description: \(description)")
    }
}

